import type { LeverConfig, Preset, Store, ZoneId } from '../types';

export const ZONES: { id: ZoneId; label: string; popKey: keyof Store }[] = [
  { id: 'zone1', label: 'Moins de 10 min en voiture', popKey: 'pop10min' },
  { id: 'zone2', label: 'Moins de 20 min en voiture', popKey: 'pop20min' },
  { id: 'zone3', label: 'Moins de 30 min en voiture', popKey: 'pop30min' },
  { id: 'zone4', label: 'Zone custom', popKey: 'popCustom' },
];

/** Retourne la population moyenne de la zone sélectionnée parmi tous les magasins actifs. */
export function getZoneAvgPop(stores: Store[], zoneId: ZoneId | undefined): number {
  if (!stores || stores.length === 0) return 140000;
  const key = ZONES.find(z => z.id === zoneId)?.popKey ?? 'pop10min';
  const sum = stores.reduce((acc, s) => acc + (Number(s[key]) || 0), 0);
  return Math.round(sum / stores.length) || 140000;
}

/** @deprecated Utiliser getZoneAvgPop(stores, zoneId) à la place. */
export function getZoneMultiplier(_zoneId: ZoneId | undefined): number {
  return 1;
}

